Here are the public test cases for feature12_apply_extensions_in_api_responses:
{
  "cases": [
    {
      "expected_output": "{\"data\":{\"id\":1,\"name\":\"Tyrell\",\"organization_id\":1},\"status_code\":200}\n",
      "input": {
        "operation": "api_response"
      }
    },
    {
      "expected_output": "{\"data\":{\"cars\":[{\"variant\":\"P100D\"}]},\"status_code\":200}\n",
      "input": {
        "operation": "api_response",
        "query": {
          "exclude": "cars__id",
          "expand": "cars",
          "only": "cars"
        }
      }
    },
    {
      "expected_output": "{\"data\":{\"id\":1,\"name\":\"Tyrell\",\"organization_id\":\"mbcN\"},\"lookup\":\"94Fp\",\"status_code\":200}\n",
      "input": {
        "lookup": "owner_external_id",
        "operation": "external_lookup"
      }
    },
    {
      "expected_output": "{\"data\":{\"detail\":\"Not found.\"},\"lookup\":\"XPh7\",\"status_code\":404}\n",
      "input": {
        "lookup": "other_model_external_id",
        "operation": "external_lookup"
      }
    }
  ],
  "description": "Apply request-supplied extension instructions through an API view response and preserve framework-visible response signals."
}

Here are the public test cases for feature1_select_requested_fields:
{
  "cases": [
    {
      "expected_output": "{\"id\":1,\"manufacturer\":{\"id\":1,\"name\":\"Tesla\"},\"name\":\"Model S\",\"skus\":[{\"id\":1,\"owners\":[{\"email\":\"t.wellick@e-corp.com\",\"id\":1,\"name\":\"Tyrell\",\"organization\":{\"id\":1,\"name\":\"E Corp\"}}],\"variant\":\"P100D\"},{\"id\":2,\"owners\":[],\"variant\":\"70\"}]}\n",
      "input": {
        "operation": "select_fields"
      }
    },
    {
      "expected_output": "{\"id\":1}\n",
      "input": {
        "fields": [
          "id"
        ],
        "operation": "select_fields"
      }
    },
    {
      "expected_output": "{\"skus\":[{\"id\":1,\"variant\":\"P100D\"},{\"id\":2,\"variant\":\"70\"}]}\n",
      "input": {
        "fields": [
          "skus__id",
