Here are the public test cases for feature5_expand_related_resources:
{
  "cases": [
    {
      "expected_output": "{\"id\":1,\"name\":\"Tyrell\",\"organization_id\":1}\n",
      "input": {
        "operation": "expand_resources"
      }
    },
    {
      "expected_output": "{\"id\":1,\"name\":\"Tyrell\",\"organization\":{\"id\":1,\"name\":\"E Corp\"},\"organization_id\":1}\n",
      "input": {
        "expand": [
          "organization"
        ],
        "operation": "expand_resources"
      }
    },
    {
      "expected_output": "{\"cars\":[1],\"id\":1,\"name\":\"Tyrell\",\"organization_id\":1}\n",
      "input": {
        "expand_id_only": [
          "cars"
        ],
        "operation": "expand_resources"
      }
    },
    {
      "expected_output": "{\"cars\":[{\"id\":1,\"model\":{\"id\":1,\"manufacturer\":{\"id\":1,\"name\":\"Tesla\"},\"manufacturer_id\":1,\"name\":\"Model S\"},\"model_id\":1,\"variant\":\"P100D\"}],\"id\":1,\"name\":\"Tyrell\",\"organization_id\":1}\n",
      "input": {
        "expand": [
          "cars__model__manufacturer"
        ],
        "operation": "expand_resources"
      }
    },
    {
      "expected_output": "{\"cars\":[{\"id\":1,\"model\":{\"id\":1,\"manufacturer_id\":1,\"name\":\"Model S\",\"skus\":[1,2]},\"model_id\":1,\"variant\":\"P100D\"}],\"id\":1,\"name\":\"Tyrell\",\"organization_id\":1}\n",
      "input": {
        "expand_id_only": [
          "cars__model__skus"
        ],
        "operation": "expand_resources"
      }
    },
    {
      "expected_output": "{\"is_model\":false,\"sku\":{\"id\":1,\"model_id\":1,\"variant\":\"P100D\"}}\n",
      "input": {
        "expand": [
          "sku"
        ],
        "operation": "expand_resources",
        "profile": "plain_object"
      }
    }
  ],
  "description": "Serialize a base owner record while expanding requested related resources fully, as identifiers only for collection leaves, or as additional same-record information."
}

