Here are the public test cases for feature7_deserialize_expandable_relations:
{
  "cases": [
    {
      "expected_output": "{\"is_valid\":true,\"validated_data\":{\"name\":\"Ka\"}}\n",
      "input": {
        "data": {
          "manufacturer_id": 1,
          "name": "Ka"
        },
        "operation": "validate_write",
        "profile": "read_only_relation"
      }
    },
    {
      "expected_output": "{\"is_valid\":true,\"validated_data\":{\"manufacturer_id\":1,\"manufacturer_id_resolved\":{\"id\":1,\"name\":\"Tesla\",\"record_type\":\"manufacturer\"},\"name\":\"Ka\"}}\n",
      "input": {
        "data": {
          "manufacturer_id": 1,
          "name": "Ka"
        },
        "operation": "validate_write",
        "profile": "writable_relation"
      }
    },
    {
      "expected_output": "{\"errors\":{\"manufacturer_id\":[\"This field is required.\"]},\"is_valid\":false}\n",
      "input": {
        "data": {
          "name": "Ka"
        },
        "operation": "validate_write",
        "profile": "writable_relation"
      }
    }
  ],
  "description": "Validate write input for expandable relations, leaving read-only relation identifiers out of validated data and resolving writable relation identifiers to their target records."
}

